import React, { useContext } from 'react';
import { Container } from 'react-bootstrap'; 
// Importaciones de Contextos mínimas para pasar el check de build
import { AuthContext } from '../context/AuthContext';
import { SettingsContext } from '../context/SettingsContext'; 
import HeaderSkeleton from './HeaderSkeleton'; 

const Header = () => {
  // Solo se usan para evitar errores de linting/contextos
  const { loading: authLoading } = useContext(AuthContext); 
  const { loading: settingsLoading } = useContext(SettingsContext);

  const isLoading = authLoading || settingsLoading;

  if (isLoading) {
     return <HeaderSkeleton />;
  }
  
  // Clase base para la prueba: oscuro y redondeado en la parte inferior.
  return (
    // CLASE CRÍTICA: rounded-b-xl para el redondeo inferior.
    <header 
      className="w-full sticky top-0 z-50 transition-all duration-300 shadow-md rounded-b-xl"
      style={{ backgroundColor: 'var(--brand-dark)' }} 
    >
      {/* Contenedor completamente vacío para aislar el contenedor del header */}
      <Container className="py-5"> 
        {/* Dejamos este espacio para que tenga altura, pero sin contenido */}
        <div className="d-flex justify-content-center align-items-center">
            {/* Prueba de Header Básico */}
            <h1 className="text-white text-lg m-0">Header de Prueba</h1>
        </div>
      </Container>
    </header>
  );
};

export default Header;
